  UPDATE esg.tb_notice_alarm_his
  SET read_yn = #{readYn}
    , read_at = NOW()
    , updated_at = NOW()
    , updated_by = #{userId}
WHERE user_id = #{userId}
  AND alarm_dt = #{alarmDt}
  AND alarm_seq = #{alarmSeq}

UPDATE esg.tb_emergency_alarm_his
SET read_yn = #{readYn}
, read_at = NOW()
, updated_at = NOW()
, updated_by = #{userId}
WHERE user_id = #{userId}
AND alarm_dt = #{alarmDt}
AND alarm_seq = #{alarmSeq}

UPDATE esg.tb_training_plan_implementation_alarm_his
SET read_yn = #{readYn}
, read_at = NOW()
, updated_at = NOW()
, updated_by = #{userId}
WHERE user_id = #{userId}
AND alarm_dt = #{alarmDt}
AND alarm_seq = #{alarmSeq}
